class Solution:
    def minimumRounds(self, tasks):
        from collections import Counter
        counts = Counter(tasks)
        total = 0
        for c in counts.values():
            if c == 1:
                return -1
            # greedily peel off threes, then handle the remainder
            rounds = 0
            while c > 0:
                if c % 3 == 0:
                    rounds += c // 3
                    c = 0
                elif c == 2 or c == 4:
                    rounds += 1
                    c -= 2
                else:
                    rounds += 1
                    c -= 3
            total += rounds
        return total

