var minimumRounds = function(tasks) {
    const counts = new Map();
    for (const t of tasks) counts.set(t, (counts.get(t) || 0) + 1);
    let total = 0;
    for (const c of counts.values()) {
        if (c === 1) return -1;
        total += Math.floor((c + 2) / 3);
    }
    return total;
};
